function mapFamily(raw) {
  const f = (raw || "").toLowerCase();
  if (f === "enamel") return "enamel-pf";
  if (f === "primer") return "primer-gf";
  if (f === "lacquer" || f === "paint" || f === "putty" || f === "solvent") return f;
  return raw || "other";
}

function normalizeProduct(raw) {
  const name = raw.name || raw.fullName || `${raw.typeWord || ""} ${raw.series || ""}`.trim();
  const lineCode = String(raw.lineCode ?? raw.series ?? "").trim();
  const code = String(raw.code ?? "").trim();
  const typeWord = raw.typeWord || (name.split(" ")[0] || "Материал");
  const stripToken = lineCode || code;
  const variant =
    raw.variant ||
    name.replace(typeWord, "").replace(stripToken, "").trim() ||
    name;
  const seriesDisplay = lineCode || typeWord;

  return {
    id: raw.id || `p-${Math.random().toString(36).slice(2, 9)}`,
    family: mapFamily(raw.family),
    code,
    lineCode: lineCode || "",
    series: seriesDisplay,
    typeWord,
    fullName: name,
    name,
    variant,
    bucketKg: roundCatalogNum(raw.bucketKg),
    drumKg: roundCatalogNum(raw.drumKg),
    priceNoNdsPerKg: roundCatalogNum(raw.priceNoNdsPerKg),
    priceNdsPerKg: roundCatalogNum(raw.priceNdsPerKg),
  };
}

function roundCatalogNum(v) {
  if (v === "" || v === undefined || v == null) return null;
  const n = Number(v);
  if (!Number.isFinite(n) || n < 0) return null;
  if (typeof window.dpRoundMoney === "function") return window.dpRoundMoney(n);
  return Math.round(n * 100) / 100;
}

window.dpNormalizeProduct = normalizeProduct;

function hydrateProductsFromData() {
  if (!Array.isArray(window.PRODUCTS_DATA)) return;
  PRODUCTS.length = 0;
  const merge =
    typeof window.dpMergeCatalogRaw === "function" ? window.dpMergeCatalogRaw : (r) => r;
  if (typeof window.dpApplyNumericCodesToCatalogData === "function") {
    window.dpApplyNumericCodesToCatalogData(window.PRODUCTS_DATA);
  }
  PRODUCTS.push(...window.PRODUCTS_DATA.map((raw) => normalizeProduct(merge(raw))));
}
hydrateProductsFromData();

const CART_AUTH_OWNER_KEY = "dp_cart_auth_owner";
const CART_STORAGE_KEY_GUEST = "dp_cart_guest";
const CART_STORAGE_KEY_PREFIX_AUTH = "dp_cart_auth_";

function cartStorageKeyForOwner(owner) {
  if (!owner) return CART_STORAGE_KEY_GUEST;
  return `${CART_STORAGE_KEY_PREFIX_AUTH}${encodeURIComponent(owner)}`;
}

function normalizeStoredCart(raw) {
  if (!Array.isArray(raw)) return [];
  return raw.filter(
    (it) =>
      it &&
      typeof it.productId === "string" &&
      (it.packType === "bucket" || it.packType === "drum" || it.packType === "jar") &&
      typeof it.qty === "number" &&
      (it.mode === "retail" || it.mode === "wholesale")
  );
}

function currentCartAuthOwner() {
  try {
    const tok = localStorage.getItem("authToken");
    if (!tok) return "";
    const u = JSON.parse(localStorage.getItem("authUser") || "null");
    const id = u?.id != null ? String(u.id) : "";
    const email = String(u?.email || "").trim().toLowerCase();
    return id || email || "auth";
  } catch {
    return "";
  }
}

function loadCartForOwner(owner) {
  try {
    const key = cartStorageKeyForOwner(owner);
    const raw = JSON.parse(localStorage.getItem(key) || "[]");
    if (owner) {
      localStorage.setItem(CART_AUTH_OWNER_KEY, owner);
    } else {
      localStorage.removeItem(CART_AUTH_OWNER_KEY);
    }
    return normalizeStoredCart(raw);
  } catch {
    return [];
  }
}

function enforceCartAuthIsolationOnBoot() {
  try {
    const owner = String(localStorage.getItem(CART_AUTH_OWNER_KEY) || "");
    const current = currentCartAuthOwner();
    if (owner && !current) {
      localStorage.removeItem(CART_AUTH_OWNER_KEY);
    }
  } catch {
    /* ignore */
  }
}

