function t(key) {
  const loc = I18N[state.lang];
  if (loc && Object.prototype.hasOwnProperty.call(loc, key)) return loc[key];
  return Object.prototype.hasOwnProperty.call(I18N.ru, key) ? I18N.ru[key] : key;
}

function dv2Esc(s) {
  return String(s ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

function dv2MediaUrl(p) {
  const s = String(p || "").trim();
  if (typeof window.dpResolveMediaUrl === "function") return window.dpResolveMediaUrl(s);
  return s;
}

function dv2StripPriceLeadIntro(lead) {
  return String(lead ?? "")
    .replace(/\s+от\s*$/i, "")
    .replace(/\s+від\s*$/i, "")
    .replace(/\s+from\s*$/i, "")
    .trimEnd()
    .trim();
}

function dv2DefaultRowPriceLabels() {
  const lang = String(document.documentElement.lang || "ru")
    .slice(0, 2)
    .toLowerCase();
  if (lang === "uk") return ["від", "до"];
  if (lang === "en") return ["from", "to"];
  return ["от", "до"];
}

function dv2FillPriceLine(el, row) {
  if (!el || !row) return;
  el.textContent = "";
  el.removeAttribute("hidden");
  el.classList.remove("dv2-row__price--split");

  const from = String(row.priceFrom ?? "").trim();
  const to = String(row.priceTo ?? "").trim();
  const lead = String(row.priceLead ?? "");
  const mid = String(row.priceMid ?? "");
  const trailRaw = row.priceTrail;
  const trail = String(trailRaw ?? "");
  const lblFromIn = String(row.priceFromLabel ?? "").trim();
  const lblToIn = String(row.priceToLabel ?? "").trim();
  const [defA, defB] = dv2DefaultRowPriceLabels();

  if (from && to) {
    el.classList.add("dv2-row__price--split");
    const introText = dv2StripPriceLeadIntro(lead);
    if (introText) {
      const intro = document.createElement("span");
      intro.className = "dv2-row__price-intro";
      intro.textContent = introText;
      el.appendChild(intro);
    }

    const cols = document.createElement("span");
    cols.className = "dv2-row__price-cols";
    const lblA = lblFromIn || defA;
    const lblB = lblToIn || defB;
    for (const [label, val] of [
      [lblA, from],
      [lblB, to],
    ]) {
      const col = document.createElement("span");
      col.className = "dv2-row__price-col";
      const lab = document.createElement("span");
      lab.className = "dv2-label";
      lab.textContent = label;
      const s = document.createElement("strong");
      s.textContent = val;
      col.append(lab, s);
      cols.appendChild(col);
    }
    el.appendChild(cols);

    if (trail.trim()) {
      const tr = document.createElement("span");
      tr.className = "dv2-row__price-trail";
      tr.textContent = trail;
      el.appendChild(tr);
    }
    return;
  }

  const inner = document.createElement("span");
  inner.className = "dv2-row__price-inner";
  const seq = [
    [lead, false],
    [from, true],
    [mid, false],
    [to, true],
    [trail, false],
  ];
  for (const [txt, bold] of seq) {
    const t = String(txt ?? "");
    if (!t) continue;
    if (bold) {
      const strong = document.createElement("strong");
      strong.textContent = t;
      inner.appendChild(strong);
    } else {
      const sp = document.createElement("span");
      sp.className = "dv2-row__price-txt";
      sp.textContent = t;
      inner.appendChild(sp);
    }
  }
  if (inner.childNodes.length) el.appendChild(inner);
  if (!el.firstChild) el.hidden = true;
}

function dv2FillUlFromLines(ul, raw) {
  if (!ul) return;
  const lines = String(raw ?? "")
    .split("\n")
    .map((x) => x.trim())
    .filter(Boolean);
  ul.innerHTML = lines.map((line) => `<li>${dv2Esc(line)}</li>`).join("");
}

function applyDeliveryPageV2(v2) {
  if (document.body?.dataset?.page !== "delivery") return;
  if (!v2 || typeof v2 !== "object") return;

  const setText = (key, val) => {
    document.querySelectorAll(`[data-dp-dv2="${key}"]`).forEach((el) => {
      if (el instanceof HTMLAnchorElement) return;
      el.textContent = val != null ? String(val) : "";
    });
  };

  const w = v2.wideCard || {};
  const setBlock = (name, vis) => {
    const el = document.querySelector(`[data-dp-dv2-block="${name}"]`);
    if (el) el.hidden = vis === false;
  };
  setBlock("wide", w.visible);
  setBlock("side", (v2.sideCard || {}).visible);
  setBlock("faq", (v2.faq || {}).visible);

  setText("wide.title", w.title);
  setText("wide.sub", w.sub);
  setText("wide.pfLabel", w.priceFromLabel);
  setText("wide.pf", w.priceFrom);
  setText("wide.ptLabel", w.priceToLabel);
  setText("wide.pt", w.priceTo);

  const wImg = document.querySelector('[data-dp-dv2="wide.img"]');
  if (wImg instanceof HTMLImageElement) {
    const src = dv2MediaUrl(w.imageUrl);
    if (src) wImg.src = src;
    if (w.imageAlt != null) wImg.alt = String(w.imageAlt);
  }
  const wCta = document.querySelector('[data-dp-dv2="wide.cta"]');
  if (wCta instanceof HTMLAnchorElement) {
    if (w.ctaLabel) wCta.textContent = w.ctaLabel;
    if (w.ctaHref) wCta.setAttribute("href", w.ctaHref);
  }

  const sc = v2.sideCard || {};
  setText("side.title", sc.title);
  setText("side.sub", sc.sub);
  setText("side.note", sc.note);

  const fq = v2.faq || {};
  setText("faq.title", fq.title);
  const fqRoot = document.querySelector("[data-dp-dv2-faq-root]");
  if (fqRoot && Array.isArray(fq.items)) {
    fqRoot.innerHTML = fq.items
      .filter((it) => it && (String(it.q || "").trim() || String(it.body || "").trim()))
      .map(
        (it) =>
          `<details><summary><span class="dv2-faq__q">${dv2Esc(it.q)}</span><span class="dv2-faq__chev" aria-hidden="true">›</span></summary><div class="dv2-faq__body">${dv2Esc(
            it.body || ""
          ).replace(/\n/g, "<br />")}</div></details>`
      )
      .join("");
  }

  function applyRow(rowKey, dataKey, prefix, row, hasPills, pickup) {
    const r = row || {};
    const art = document.querySelector(`[data-dp-dv2-row="${rowKey}"]`);
    if (art) art.hidden = r.visible === false;

    const img = document.querySelector(`[data-dp-dv2="${prefix}.img"]`);
    if (img instanceof HTMLImageElement) {
      const src = dv2MediaUrl(r.imageUrl);
      if (src) img.src = src;
      if (r.imageAlt != null) img.alt = String(r.imageAlt);
    }
    setText(`${prefix}.h3`, r.title);
    if (hasPills) {
      setText(`${prefix}.p1`, r.pill1);
      setText(`${prefix}.p2`, r.pill2);
      const pills = document.querySelector(`[data-dp-dv2="${prefix}.pills"]`);
      const hide = !String(r.pill1 || "").trim() && !String(r.pill2 || "").trim();
      if (pills) pills.hidden = hide;
    }
    const priceEl = document.querySelector(`[data-dp-dv2-row-price="${dataKey}"]`);
    if (priceEl && !pickup) dv2FillPriceLine(priceEl, r);

    const cta = document.querySelector(`[data-dp-dv2="${prefix}.cta"]`);
    if (cta instanceof HTMLAnchorElement) {
      if (r.ctaLabel) cta.textContent = r.ctaLabel;
      if (r.ctaHref) cta.setAttribute("href", r.ctaHref);
    }

    if (!pickup) {
      setText(`${prefix}.a1t`, r.aside1Title);
      setText(`${prefix}.a1p`, r.aside1Text);
      setText(`${prefix}.a2t`, r.aside2Title);
      dv2FillUlFromLines(document.querySelector(`[data-dp-dv2="${prefix}.a2ul"]`), r.aside2List);
    } else {
      const addr = document.querySelector(`[data-dp-dv2="${prefix}.addr"]`);
      if (addr) addr.textContent = String(r.addressText || "").replace(/\r\n/g, "\n");
      setText(`${prefix}.at`, r.asideTitle);
      setText(`${prefix}.ap`, r.asideText);
    }
  }

  const rows = v2.rows || {};
  applyRow("local", "local", "row.local", rows.local, true, false);
  applyRow("national", "national", "row.nat", rows.national, true, false);
  applyRow("pickup", "pickup", "row.pickup", rows.pickup, false, true);
}

/** Тексты «Доставка по Украине» с сервера (site-content.json), по языку интерфейса. */
function applyDeliveryUkraineCopy() {
  const pack = window.DP_DELIVERY_UKRAINE;
  if (!pack || typeof pack !== "object") return;
  const lang = state.lang === "uk" ? "uk" : "ru";
  const row = pack[lang] || pack.ru;
  if (!row || typeof row !== "object") return;

  document.querySelectorAll('[data-dp-delivery="navUtility"]').forEach((el) => {
    if (row.navUtilityVisible === false) {
      el.hidden = true;
      return;
    }
    el.hidden = false;
    if (row.navUtility) el.textContent = row.navUtility;
  });
  document.querySelectorAll('[data-dp-delivery="footerLink"]').forEach((el) => {
    if (row.footerLinkVisible === false) {
      el.hidden = true;
      return;
    }
    el.hidden = false;
    if (row.footerLink) el.textContent = row.footerLink;
  });

  const h1 = document.querySelector('[data-dp-delivery="pageH1"]');
  if (h1) {
    if (row.pageH1Visible === false) {
      h1.hidden = true;
    } else {
      h1.hidden = false;
      if (row.pageH1) h1.textContent = row.pageH1;
    }
  }
  const lead = document.querySelector('[data-dp-delivery="pageLead"]');
  if (lead) {
    if (row.pageLeadVisible === false) {
      lead.hidden = true;
    } else {
      lead.hidden = false;
      if (row.pageLead) lead.textContent = row.pageLead;
    }
  }

  if (document.body?.dataset?.page === "delivery" && row.pageH1Visible !== false && row.pageH1) {
    document.title = `DP Coatings — ${row.pageH1}`;
  }

  if (document.body?.dataset?.page === "delivery" && row.pageV2) {
    applyDeliveryPageV2(row.pageV2);
  }
}

window.applyDeliveryUkraineCopy = applyDeliveryUkraineCopy;

function applyTranslations() {
  document.documentElement.lang = state.lang;
  document.querySelectorAll("[data-i18n]").forEach((el) => {
    const key = el.dataset.i18n;
    el.textContent = t(key);
  });
  if (nodes.search) nodes.search.placeholder = t("searchPlaceholder");

  document.querySelectorAll("[data-i18n-placeholder]").forEach((el) => {
    const key = el.dataset.i18nPlaceholder;
    if (key) el.setAttribute("placeholder", t(key));
  });

  document.querySelectorAll("[data-i18n-alt]").forEach((el) => {
    const key = el.dataset.i18nAlt;
    if (key) el.setAttribute("alt", t(key));
  });

  document.querySelectorAll("[data-i18n-aria-label]").forEach((el) => {
    const key = el.dataset.i18nAriaLabel;
    if (key) el.setAttribute("aria-label", t(key));
  });

  document.querySelectorAll("[data-i18n-title]").forEach((el) => {
    const key = el.dataset.i18nTitle;
    if (key) el.setAttribute("title", t(key));
  });

  if (typeof window.__updateHeroShowcaseSlideshowI18n === "function") window.__updateHeroShowcaseSlideshowI18n();
  if (typeof window.applyDeliveryUkraineCopy === "function") window.applyDeliveryUkraineCopy();
  if (typeof window.__syncCatalogNavButtons === "function") window.__syncCatalogNavButtons();
  if (typeof window.__renderTypeProperties === "function") window.__renderTypeProperties();
  const activeNavBtn = document.querySelector("[data-nav-value].active");
  if (activeNavBtn) state.activeNavLabel = activeNavBtn.textContent.trim();
  if (typeof window.__renderProductsShowcase === "function") window.__renderProductsShowcase(state.activeNavLabel || t("catalogNavAll"));
  const navHint = document.getElementById("catalog-nav-hint");
  if (navHint) navHint.textContent = state.purposeFilter ? purposeInfoText(state.purposeFilter) : "";
  if (nodes.siteSearchInput) {
    const homePh = nodes.siteSearchInput.closest(".home-site-search");
    nodes.siteSearchInput.setAttribute(
      "placeholder",
      homePh ? t("siteSearchPlaceholderHome") : t("siteSearchPlaceholder")
    );
    nodes.siteSearchInput.setAttribute("aria-label", homePh ? t("siteSearchPlaceholderHome") : t("siteSearchAria"));
  }
  if (nodes.siteSearchSubmit) {
    if (!nodes.siteSearchSubmit.classList.contains("site-search-submit--icon")) {
      nodes.siteSearchSubmit.textContent = t("siteSearchSubmit");
    }
    const homeTg = nodes.siteSearchSubmit.closest(".home-site-search");
    if (homeTg && nodes.siteSearchSubmit.classList.contains("site-search-submit--icon")) {
      const open = homeTg.classList.contains("is-open");
      nodes.siteSearchSubmit.setAttribute("aria-label", open ? t("siteSearchAriaSubmit") : t("siteSearchOpen"));
      nodes.siteSearchSubmit.setAttribute("aria-expanded", open ? "true" : "false");
    } else {
      nodes.siteSearchSubmit.setAttribute("aria-label", t("siteSearchAriaSubmit"));
    }
  }
  renderNavProductsMenu();
  renderNews();
  renderAdviceRecommendations();
  renderAdviceImages();
  rotateMonthlyAdviceCards();
  renderStructuredFooterFromProjectData();
  if (nodes.languageSwitcher) nodes.languageSwitcher.value = state.lang;
  /* После data-i18n обновляем [data-ru][data-uk] (account-payment и др.): иначе до init site-lang и script.js расходились по языку. */
  if (typeof window.dpApplyDataLangAttrs === "function") {
    window.dpApplyDataLangAttrs();
  }
}

