function inferPurposes(product) {
  const n = `${product.name || ""} ${product.series || ""} ${product.variant || ""}`.toLowerCase();
  const out = [];
  if (n.includes("гф-021") || n.includes("грунтов")) out.push("Для грунтования перед покраской");
  if (n.includes("терм") || n.includes("420")) out.push("Термостойкие покрытия");
  if (n.includes("электро") || n.includes("гф-92")) out.push("Электроизоляционные материалы");
  if (n.includes("металл") || n.includes("эмаль") || n.includes("пф-")) out.push("Промышленные покрытия по металлу");
  if (product.family === "solvent") out.push("Растворители для разбавления краски");
  if (product.family === "enamel-pf" || product.family === "enamel") out.push("Строительные и универсальные эмали");
  if (!out.length) out.push("Универсальное применение");
  return [...new Set(out)];
}

function detailedProductText(product) {
  const purposes = inferPurposes(product);
  const pack = [
    product.bucketKg ? `ведро ${product.bucketKg} кг` : null,
    product.drumKg ? `барабан ${product.drumKg} кг` : null,
    "банка 0.9/2.8/3.0 кг",
  ]
    .filter(Boolean)
    .join(", ");

  const retail = formatPrice(product.priceNdsPerKg);
  const wholesale = formatPrice(product.priceNoNdsPerKg);
  const code = product.series || product.code || "";

  const familyText =
    product.family === "primer-gf" || product.family === "primer"
      ? "Материал формирует адгезионный и антикоррозионный слой, снижает расход финишной эмали и повышает стабильность системы покрытия."
      : product.family === "enamel-pf" || product.family === "enamel"
        ? "Материал образует декоративно-защитное покрытие для внешних и внутренних работ. Подходит для систем с предварительным грунтованием."
        : product.family === "solvent"
          ? "Материал используется для доведения ЛКМ до рабочей вязкости и настройки технологичности нанесения."
          : "Материал используется в промышленных и строительных ЛКМ-системах как часть комплексного покрытия.";

  return `
    <p><strong>${product.name}</strong> (${code}) — позиция из актуального прайс-листа с прозрачной ценой за кг.</p>
    <p>${familyText}</p>
    <p><strong>Назначение:</strong> ${purposes.join(", ")}.</p>
    <p><strong>Фасовка:</strong> ${pack}. <strong>Цена:</strong> розница ${retail} грн/кг, опт ${wholesale} грн/кг.</p>
    <p><strong>Рекомендация:</strong> перед закупкой согласуйте основание, условия эксплуатации и требуемую стойкость покрытия, чтобы менеджер подобрал оптимальную систему.</p>
  `;
}

function defaultPackTypeForCatalog(p) {
  if (!p) return null;
  if (p.bucketKg != null) return "bucket";
  if (p.drumKg != null) return "drum";
  return null;
}

function renderProducts() {
  if (!nodes.products) return;
  const all = getVisibleProducts();
  const totalPages = Math.max(1, Math.ceil(all.length / state.pageSize));
  if (state.page > totalPages) state.page = totalPages;
  const start = (state.page - 1) * state.pageSize;
  const items = all.slice(start, start + state.pageSize);
  nodes.products.innerHTML = "";
  if (!items.length) {
    nodes.products.innerHTML = `<article class="card"><h3>${t("navProducts")}</h3><p class="meta">По текущим фильтрам позиции не найдены. Измените фильтры или поиск.</p></article>`;
    if (nodes.pagination) nodes.pagination.innerHTML = "";
    return;
  }
  items.forEach((p) => {
    const detailsText = detailedProductText(p);
    const retailUnit = unitPricePerKg(p, "retail");
    const wholesaleUnit = unitPricePerKg(p, "wholesale");
    const img = productImageDataUri(p);
    const badge = productImageBadge(p);

    const bucketExists = p.bucketKg != null;
    const drumExists = p.drumKg != null;

    const modeLabel = state.customerType === "wholesale" ? t("wholesalePrice") : t("retailPrice");
    const bucketTotal = bucketExists ? calcPackTotal(p, "bucket", state.customerType) : null;
    const drumTotal = drumExists ? calcPackTotal(p, "drum", state.customerType) : null;
    const bucketCanAdd = bucketExists && bucketTotal != null;
    const drumCanAdd = drumExists && drumTotal != null;

    const defPack = defaultPackTypeForCatalog(p);
    const defCanAdd = defPack === "bucket" ? bucketCanAdd : defPack === "drum" ? drumCanAdd : false;

    const card = document.createElement("article");
    card.className = "card";
    card.innerHTML = `
      <div class="product-media">
        <img class="product-img" src="${img}" alt="${escapeHtml(p.typeWord)} ${escapeHtml(productBadgeSeriesLine(p))}" loading="lazy" onerror="this.onerror=null;this.src='assets/product-template.png';" />
        <div class="product-badge" style="--badge-accent:${badge.accent}">
          <span class="product-badge-title">${escapeHtml(badge.title)}</span>
          <span class="product-badge-series">${escapeHtml(badge.series)}</span>
        </div>
      </div>
      <h3 class="card-title">${productTypeIconSvg(p)} <span>${escapeHtml(p.typeWord)} ${escapeHtml(productBadgeSeriesLine(p))}</span></h3>
      <p class="meta">${p.variant}</p>
      <p class="price"><span>${t("retailPrice")}:</span><strong>${formatPrice(retailUnit)} ${t("perKg")}</strong></p>
      <p class="price"><span>${t("wholesalePrice")}:</span><strong>${formatPrice(wholesaleUnit)} ${t("perKg")}</strong></p>

      ${
        bucketExists
          ? `<p class="meta">${t("bucketLabel")}: ${p.bucketKg} кг — <strong>${formatMoney(bucketTotal)}</strong> (${modeLabel})</p>`
          : `<p class="meta">${t("bucketLabel")}: —</p>`
      }
      ${
        drumExists
          ? `<p class="meta">${t("drumLabel")}: ${p.drumKg} кг — <strong>${formatMoney(drumTotal)}</strong> (${modeLabel})</p>`
          : `<p class="meta">${t("drumLabel")}: —</p>`
      }

      <div class="card-actions card-actions--twobtn">
        <button class="btn btn-primary" type="button" data-add-one="${p.id}" data-pack="${defPack || ""}" ${
      defPack && defCanAdd ? "" : "disabled"
    }>${t("productCardToCart")}</button>
        <button class="btn btn-ghost" type="button" data-pay="${p.id}" ${defPack && defCanAdd ? "" : "disabled"}>${t(
      "productCardPay"
    )}</button>
        <a class="btn btn-ghost product-more" href="product.html?id=${encodeURIComponent(p.id)}">${t("moreButton")}</a>
      </div>

      <details class="product-details">
        <summary>${t("productDetailsSummary")}</summary>
        <div class="product-details-text">${detailsText}</div>
      </details>
    `;
    nodes.products.appendChild(card);
  });

  if (nodes.pagination) {
    nodes.pagination.innerHTML = `
      <button class="btn btn-ghost" type="button" data-page="${Math.max(1, state.page - 1)}" ${state.page === 1 ? "disabled" : ""}>←</button>
      <span class="meta">Страница ${state.page} из ${totalPages}</span>
      <button class="btn btn-ghost" type="button" data-page="${Math.min(totalPages, state.page + 1)}" ${state.page === totalPages ? "disabled" : ""}>→</button>
    `;
  }
}

