function renderNavProductsMenu() {
  const menu = document.getElementById("nav-products-menu");
  if (!menu) return;

  const byFamily = new Map();
  PRODUCTS.forEach((p) => {
    const fam = p.family || "other";
    if (!byFamily.has(fam)) byFamily.set(fam, []);
    byFamily.get(fam).push(p);
  });

  const titles = {
    "enamel-pf": t("catEnamelPf"),
    "primer-gf": t("catPrimerGf"),
    enamel: "Эмали",
    primer: "Грунтовки",
    paint: "Краски",
    lacquer: "Лаки",
    putty: "Шпатлевки",
    solvent: "Растворители",
    other: "Прочее",
  };

  const purposeMap = new Map();
  PRODUCTS.forEach((p) => {
    inferPurposes(p).forEach((purpose) => {
      if (!purposeMap.has(purpose)) purposeMap.set(purpose, []);
      purposeMap.get(purpose).push(p);
    });
  });

  function col(title, family, items) {
    const buttons = items
      .map(
        (p) =>
          `<button class="nav-product-item" type="button" data-nav-family="${family}" data-nav-id="${p.id}">${navGroupIcon(family)} ${p.name || `${p.typeWord || ""} ${p.series || ""}`}</button>`
      )
      .join("");
    return `
      <div class="nav-col">
        <div class="nav-col-head">
          <img class="nav-col-thumb" src="${navCategoryImage(family)}" alt="${escapeHtml(title)}" loading="lazy" />
          <h4>${title}</h4>
        </div>
        ${buttons}
      </div>
    `;
  }

  const order = ["enamel-pf", "primer-gf", "enamel", "primer", "paint", "lacquer", "putty", "solvent", "other"];
  const byTypeHtml = order
    .filter((fam) => byFamily.has(fam))
    .map((fam) => col(titles[fam] || fam, fam, byFamily.get(fam).slice(0, 40)))
    .join("");

  const typeCardsHtml = order
    .filter((fam) => byFamily.has(fam))
    .map((fam) => {
      const title = titles[fam] || fam;
      const count = byFamily.get(fam).length;
      return `
        <button class="nav-type-card" type="button" data-nav-only-family="${fam}">
          <img class="nav-type-card-img" src="${navCategoryImage(fam)}" alt="${escapeHtml(title)}" loading="lazy" />
          <span>${title}</span>
          <small>${count} поз.</small>
        </button>
      `;
    })
    .join("");

  const purposeCols = [...purposeMap.entries()]
    .sort((a, b) => b[1].length - a[1].length)
    .slice(0, 6)
    .map(([purpose, items]) => {
      const btns = items
        .slice(0, 18)
        .map(
          (p) =>
            `<button class="nav-product-item" type="button" data-nav-family="${p.family}" data-nav-id="${p.id}">${navGroupIcon("purpose")} ${p.series || p.code || p.name}</button>`
        )
        .join("");
      return `<div class="nav-col"><h4>${purpose}</h4>${btns}</div>`;
    })
    .join("");

  menu.innerHTML = `
    <div class="nav-menu-title">По типу лакокрасочных материалов</div>
    <div class="nav-type-cards">${typeCardsHtml}</div>
    <div class="nav-grid">${byTypeHtml}</div>
    <div class="nav-menu-title">По назначению</div>
    <div class="nav-grid">${purposeCols}</div>
  `;
}

function saveCart() {
  const owner = currentCartAuthOwner();
  const key = cartStorageKeyForOwner(owner);
  localStorage.setItem(key, JSON.stringify(state.cart));
  localStorage.setItem("cart", JSON.stringify(state.cart));
  if (owner) localStorage.setItem(CART_AUTH_OWNER_KEY, owner);
  else localStorage.removeItem(CART_AUTH_OWNER_KEY);
  if (typeof window.dpOnCartChanged === "function") {
    try {
      window.dpOnCartChanged();
    } catch {
      /* ignore */
    }
  }
}

function addToCart(productId, packType) {
  const mode = state.customerType;
  const hit = state.cart.find(
    (item) =>
      item.productId === productId && item.packType === packType && item.mode === mode
  );
  if (hit) hit.qty += 1;
  else state.cart.push({ productId, packType, qty: 1, mode });
  saveCart();
  renderCart();
}

function addJarToCart(productId, jarKg) {
  const mode = state.customerType;
  const weight = Number(jarKg);
  if (!isFinite(weight) || weight <= 0) return;
  const hit = state.cart.find(
    (item) =>
      item.productId === productId &&
      item.packType === "jar" &&
      item.mode === mode &&
      Number(item.customKg) === weight
  );
  if (hit) hit.qty += 1;
  else state.cart.push({ productId, packType: "jar", customKg: weight, qty: 1, mode });
  saveCart();
  renderCart();
}

function addToCartWithQuantity(productId, packType, qty) {
  const n = Math.max(1, Math.min(99, parseInt(String(qty), 10) || 1));
  const mode = state.customerType;
  const hit = state.cart.find(
    (item) =>
      item.productId === productId && item.packType === packType && item.mode === mode
  );
  if (hit) hit.qty += n;
  else state.cart.push({ productId, packType, qty: n, mode });
  saveCart();
  renderCart();
}

/** Авторизован ли покупатель на сайте (JWT + профиль в localStorage). Используется на странице оформления заказа. */
function dpAuthCustomerLoggedIn() {
  try {
    const tok = localStorage.getItem("authToken");
    if (!tok) return false;
    const u = JSON.parse(localStorage.getItem("authUser") || "null");
    return Boolean(u && (u.email || u.id != null));
  } catch {
    return false;
  }
}

/**
 * На странице checkout для гостей без входа цены строк — без НДС (priceNoNdsPerKg).
 */
function checkoutGuestNoVatPricingActive() {
  return !dpAuthCustomerLoggedIn();
}

/** Вошёл как юридическое лицо — суммы заказа с НДС (розничная колонка прайса). */
function checkoutLegalEntityVatPricingActive() {
  return dpAuthCustomerLoggedIn() && dpProfileIsLegalEntity();
}

/** Профиль в localStorage после /api/auth/me или сохранения. */
function dpProfileIsLegalEntity() {
  try {
    const u = JSON.parse(localStorage.getItem("authUser") || "null");
    return Boolean(u?.profile?.isLegalEntity);
  } catch {
    return false;
  }
}

/** Режим сумм блока «Ваш заказ» только при расчёте через checkout (guestNoVatCheckoutPricing). */
function checkoutOrderPricingKind() {
  if (!dpAuthCustomerLoggedIn()) return "guest_no_vat";
  if (dpProfileIsLegalEntity()) return "legal_entity_nds";
  return "follow_cart_modes";
}

function addJarToCartWithQuantity(productId, jarKg, qty) {
  const n = Math.max(1, Math.min(99, parseInt(String(qty), 10) || 1));
  const mode = state.customerType;
  const weight = Number(jarKg);
  if (!isFinite(weight) || weight <= 0) return;
  const hit = state.cart.find(
    (item) =>
      item.productId === productId &&
      item.packType === "jar" &&
      item.mode === mode &&
      Number(item.customKg) === weight
  );
  if (hit) hit.qty += n;
  else state.cart.push({ productId, packType: "jar", customKg: weight, qty: n, mode });
  saveCart();
  renderCart();
}

/**
 * Расчёт строк корзины и общей суммы для UI и CRM.
 * @param {{ guestNoVatCheckoutPricing?: boolean }} [options] флаг включает спец-правила страницы оформления заказа (гость / юрлицо / режим корзины)
 */
function computeCartLines(options = {}) {
  const checkoutCtx = Boolean(options.guestNoVatCheckoutPricing);
  const ck = checkoutCtx ? checkoutOrderPricingKind() : "";
  const lines = [];
  let total = 0;
  state.cart.forEach((item, index) => {
    const p = PRODUCTS.find((x) => x.id === item.productId);
    if (!p) return;
    const weight =
      item.packType === "jar" ? Number(item.customKg) : getPackWeight(p, item.packType);
    let priceMode = item.mode;
    let modeLabel =
      item.mode === "wholesale" ? t("wholesalePrice") : t("retailPrice");
    if (checkoutCtx) {
      if (ck === "guest_no_vat") {
        priceMode = "wholesale";
        modeLabel = t("checkoutGuestNoVatShort");
      } else if (ck === "legal_entity_nds") {
        priceMode = "retail";
        modeLabel = t("checkoutLegalEntityVatShort");
      } else {
        priceMode = item.mode;
        modeLabel = item.mode === "wholesale" ? t("wholesalePrice") : t("retailPrice");
      }
    }
    const unit = unitPricePerKg(p, priceMode);
    const unitTotal = weight == null || unit == null ? null : Number(weight) * Number(unit);
    const sum = unitTotal == null ? null : unitTotal * item.qty;
    if (sum != null && isFinite(Number(sum))) total += Number(sum);
    const packLabel =
      item.packType === "bucket"
        ? t("bucketLabel")
        : item.packType === "drum"
          ? t("drumLabel")
          : t("jarLabel");
    const title = `${p.typeWord} ${productBadgeSeriesLine(p)}`;
    const details = `${p.variant} · ${packLabel} ${weight ?? "—"} кг · ${modeLabel} × ${item.qty}`;
    let image = "assets/product-template.png";
    try {
      image = productImageDataUri(p);
    } catch {
      /* keep template */
    }
    const imgAlt = `${p.typeWord || ""} ${productBadgeSeriesLine(p) || ""}`.trim() || title;
    lines.push({
      index,
      title,
      details,
      qty: item.qty,
      lineTotal: sum,
      sumLabel: sum == null ? t("askPrice") : formatMoney(sum),
      image,
      imgAlt,
    });
  });
  return { lines, total };
}

function sortCartLines(lines, sort) {
  const copy = [...lines];
  const numOr = (v) => (v == null || !isFinite(Number(v)) ? null : Number(v));
  const tie = (a, b) => a.index - b.index;
  switch (sort) {
    case "price-desc":
      return copy.sort((a, b) => {
        const na = numOr(a.lineTotal);
        const nb = numOr(b.lineTotal);
        if (na == null && nb == null) return tie(a, b);
        if (na == null) return 1;
        if (nb == null) return -1;
        return nb - na || tie(a, b);
      });
    case "name-asc": {
      const loc = state.lang === "uk" ? "uk" : "ru";
      return copy.sort((a, b) => a.title.localeCompare(b.title, loc) || tie(a, b));
    }
    case "add-order":
      return copy.sort((a, b) => tie(a, b));
    case "price-asc":
    default:
      return copy.sort((a, b) => {
        const na = numOr(a.lineTotal);
        const nb = numOr(b.lineTotal);
        if (na == null && nb == null) return tie(a, b);
        if (na == null) return 1;
        if (nb == null) return -1;
        return na - nb || tie(a, b);
      });
  }
}

function buildCartSnapshotForLead(options = {}) {
  const lineOpts = Boolean(options.guestNoVatCheckout) ? { guestNoVatCheckoutPricing: true } : {};
  const { lines, total } = computeCartLines(lineOpts);
  const sorted = sortCartLines(lines, state.cartSort);
  const cartSnapshot = sorted.map(({ title, details, qty, lineTotal }) => ({
    title,
    details,
    qty,
    lineTotal: lineTotal == null ? null : Math.round(Number(lineTotal) * 100) / 100,
  }));
  return { cartSnapshot, orderTotal: Math.round(total * 100) / 100 };
}

function setCartItemQuantity(index, qty) {
  const n = Math.max(1, Math.min(99, parseInt(String(qty), 10) || 1));
  if (!state.cart[index]) return;
  state.cart[index].qty = n;
  saveCart();
  renderCart();
}

function getCheckoutLinesForView(options = {}) {
  const { lines, total } = computeCartLines(options);
  const sorted = sortCartLines(lines, state.cartSort);
  return sorted.map((L) => {
    const item = state.cart[L.index];
    const p = item ? PRODUCTS.find((x) => x.id === item.productId) : null;
    let image = "assets/product-template.png";
    if (p) {
      try {
        image = productImageDataUri(p);
      } catch {
        /* keep default */
      }
    }
    return { ...L, image, productId: item?.productId, packType: item?.packType };
  });
}

function removeFromCart(index) {
  state.cart.splice(index, 1);
  saveCart();
  renderCart();
}

function openCartDrawer() {
  nodes.cartOverlay?.classList.add("open");
  nodes.cartOverlay?.setAttribute("aria-hidden", "false");
  nodes.cartDrawer?.classList.add("open");
}

function closeCartDrawer() {
  nodes.cartOverlay?.classList.remove("open");
  nodes.cartOverlay?.setAttribute("aria-hidden", "true");
  nodes.cartDrawer?.classList.remove("open");
}

function getCartLeadOptions() {
  return {
    deliveryMethod: state.cartDelivery,
    paymentMethod: state.cartPayment,
  };
}

function renderCart() {
  if (!nodes.cartCount || !nodes.cartItems || !nodes.cartTotal) return;
  document.querySelector("#cart-drawer .cart-lead-options")?.remove();
  nodes.cartCount.textContent = String(state.cart.reduce((sum, item) => sum + item.qty, 0));
  nodes.cartItems.innerHTML = "";
  const { lines, total } = computeCartLines();
  if (nodes.cartSortSelect) nodes.cartSortSelect.value = state.cartSort;

  if (!state.cart.length) {
    nodes.cartItems.innerHTML = `<p class="meta cart-items-empty">${t("emptyCart")}</p>`;
    nodes.cartTotal.textContent = "0";
    if (nodes.cartPayBtn) {
      nodes.cartPayBtn.disabled = true;
      nodes.cartPayBtn.classList.add("is-disabled");
    }
    return;
  }

  const linesSorted = sortCartLines(lines, state.cartSort);
  linesSorted.forEach((L) => {
    const row = document.createElement("div");
    row.className = "cart-item";
    const imgSrc = escapeHtml(L.image || "assets/product-template.png");
    const imgAlt = escapeHtml(L.imgAlt || L.title || "");
    row.innerHTML = `
      <div class="cart-item-actions">
        <button class="cart-action-btn cart-item-remove-icon" type="button" data-remove="${L.index}" aria-label="${escapeHtml(t("cartRemove"))}">&times;</button>
      </div>
      <div class="cart-item-media">
        <img class="cart-item-img" src="${imgSrc}" alt="${imgAlt}" loading="lazy" decoding="async" onerror="this.onerror=null;this.src='assets/product-template.png';" />
      </div>
      <div class="cart-item-body">
        <p class="cart-item-title">${escapeHtml(L.title)}</p>
        <p class="cart-item-meta">${escapeHtml(L.details)}</p>
      </div>
      <div class="cart-item-qty">
        <button class="cart-qty-btn" type="button" data-qty-dec="${L.index}" aria-label="Уменьшить">-</button>
        <span class="cart-qty-value">${Number(L.qty) || 1}</span>
        <button class="cart-qty-btn" type="button" data-qty-inc="${L.index}" aria-label="Увеличить">+</button>
      </div>
      <div class="cart-item-price">
        <span class="cart-item-sum">${L.sumLabel}</span>
      </div>
    `;
    nodes.cartItems.appendChild(row);
  });

  nodes.cartTotal.textContent = formatPrice(total);
  if (nodes.cartPayBtn) {
    nodes.cartPayBtn.disabled = false;
    nodes.cartPayBtn.classList.remove("is-disabled");
  }
}

function openProductModal(productId) {
  const p = PRODUCTS.find((x) => x.id === productId);
  if (!p) return;

  const productModal = document.getElementById("product-modal");
  const productModalBody = document.getElementById("product-modal-body");
  const productModalTitle = document.getElementById("product-modal-title");
  if (!productModal || !productModalBody || !productModalTitle) return;

  const detailsText = p.family === "primer-gf" ? t("detailsPrimerText") : t("detailsEnamelText");

  const retailUnit = unitPricePerKg(p, "retail");
  const wholesaleUnit = unitPricePerKg(p, "wholesale");

  const pfOrGfBullets =
    p.family === "primer-gf"
      ? [t("modalGfBul1"), t("modalGfBul2"), t("modalGfBul3")]
      : [t("modalPfBul1"), t("modalPfBul2"), t("modalPfBul3")];

  const useText = p.family === "primer-gf" ? t("modalUseGf") : t("modalUsePf");
  const bundleText = p.family === "primer-gf" ? t("modalBundleGf") : t("modalBundlePf");

  const bucketExists = p.bucketKg != null;
  const drumExists = p.drumKg != null;

  const bucketRetailTotal = bucketExists ? calcPackTotal(p, "bucket", "retail") : null;
  const bucketWholesaleTotal = bucketExists ? calcPackTotal(p, "bucket", "wholesale") : null;
  const drumRetailTotal = drumExists ? calcPackTotal(p, "drum", "retail") : null;
  const drumWholesaleTotal = drumExists ? calcPackTotal(p, "drum", "wholesale") : null;
  const bucketCurrentTotal = bucketExists ? calcPackTotal(p, "bucket", state.customerType) : null;
  const drumCurrentTotal = drumExists ? calcPackTotal(p, "drum", state.customerType) : null;
  const img = productImageDataUri(p);
  const badge = productImageBadge(p);

  productModalTitle.textContent = `${p.typeWord} ${productBadgeSeriesLine(p)} — ${p.variant}`;

  function packBlock(packType) {
    const isBucket = packType === "bucket";
    const weight = getPackWeight(p, packType);
    const title = isBucket ? t("bucketLabel") : t("drumLabel");

    const totalRetail = isBucket ? bucketRetailTotal : drumRetailTotal;
    const totalWholesale = isBucket ? bucketWholesaleTotal : drumWholesaleTotal;

    return `
      <div class="meta pack-block">
        <p class="meta" style="margin:0"><strong>${title}:</strong> ${weight} кг</p>
        <p class="meta" style="margin:4px 0 0"><strong>${t("retailPrice")}:</strong> ${formatPrice(retailUnit)} ${t("perKg")} — <strong>${formatMoney(totalRetail)}</strong></p>
        <p class="meta" style="margin:4px 0 0"><strong>${t("wholesalePrice")}:</strong> ${formatPrice(wholesaleUnit)} ${t("perKg")} — <strong>${formatMoney(totalWholesale)}</strong></p>
      </div>
    `;
  }

  productModalBody.innerHTML = `
    <div class="product-media">
      <img class="product-img" src="${img}" alt="${escapeHtml(p.typeWord)} ${escapeHtml(productBadgeSeriesLine(p))}" onerror="this.onerror=null;this.src='assets/product-template.png';" />
      <div class="product-badge" style="--badge-accent:${badge.accent}">
        <span class="product-badge-title">${escapeHtml(badge.title)}</span>
        <span class="product-badge-series">${escapeHtml(badge.series)}</span>
      </div>
    </div>
    <div class="meta">${detailsText}</div>

    <h4>${t("modalTechTitle")}</h4>
    <ul>
      ${pfOrGfBullets.map((x) => `<li>${x}</li>`).join("")}
    </ul>

    <h4>${t("modalApplyTitle")}</h4>
    <p>${t("modalApplyText")}</p>

    <h4>${t("modalUseTitle")}</h4>
    <p>${useText}</p>

    <h4>${t("modalBundleTitle")}</h4>
    <p>${bundleText}</p>

    <h4>${t("packKg")}</h4>
    ${bucketExists ? packBlock("bucket") : ""}
    ${drumExists ? packBlock("drum") : ""}

    <div class="modal-actions">
      <button class="btn btn-primary" type="button" data-modal-add="${p.id}" data-modal-pack="bucket" ${
        bucketExists && bucketCurrentTotal != null ? "" : "disabled"
      }>+ ${t("addBucket")}</button>
      <button class="btn btn-primary" type="button" data-modal-add="${p.id}" data-modal-pack="drum" ${
        drumExists && drumCurrentTotal != null ? "" : "disabled"
      }>+ ${t("addDrum")}</button>
    </div>

    <h4>${t("jarPackTitle")}</h4>
    <div class="modal-actions">
      <button class="btn btn-primary" type="button" data-modal-add="${p.id}" data-modal-pack="jar" data-jar-kg="0.9">+ ${t("addJar")} 0.9 кг</button>
      <button class="btn btn-primary" type="button" data-modal-add="${p.id}" data-modal-pack="jar" data-jar-kg="2.8">+ ${t("addJar")} 2.8 кг</button>
      <button class="btn btn-primary" type="button" data-modal-add="${p.id}" data-modal-pack="jar" data-jar-kg="3.0">+ ${t("addJar")} 3.0 кг</button>
    </div>

    <p class="meta" style="margin-top:14px">${t("howLead")}</p>
  `;

  productModal.classList.add("open");
  productModal.setAttribute("aria-hidden", "false");

  if (!productModalBody.dataset.bound) {
    productModalBody.dataset.bound = "1";
    productModalBody.addEventListener("click", (e) => {
      const btn = e.target.closest("[data-modal-add]");
      if (!btn) return;
      const id = btn.dataset.modalAdd;
      const pack = btn.dataset.modalPack;
      if (!id || !pack) return;
      if (pack === "jar") {
        const jarKg = Number(btn.dataset.jarKg);
        if (!isFinite(jarKg) || jarKg <= 0) return;
        addJarToCart(id, jarKg);
      } else {
        addToCart(id, pack);
      }
      productModal.classList.remove("open");
      productModal.setAttribute("aria-hidden", "true");
    });
  }
}

function initEvents() {
  if (nodes.languageSwitcher) {
    nodes.languageSwitcher.value = state.lang;
  }
  window.addEventListener("dp-lang-change", (e) => {
    const next = e.detail && e.detail.lang;
    if (next !== "ru" && next !== "uk") return;
    state.lang = next;
    state.newsVisibleCount = 12;
    applyTranslations();
    applyHeaderAuthState();
    loadNews();
    if (document.getElementById("products")) renderProducts();
    if (document.getElementById("advice-reco-products")) renderAdviceRecommendations();
    if (document.getElementById("home-popular-products") && typeof window.__renderHomePopular === "function") {
      window.__renderHomePopular();
    }
    if (nodes.cartCount) renderCart();
  });

  const revealCatalogSection = () => {
    const section = document.getElementById("catalog");
    if (!section) return;
    section.classList.remove("hidden-on-home");
    section.setAttribute("aria-hidden", "false");
    document.body.classList.add("catalog-open");
  };

  // Sidebar: dynamic family categories
  const setCategory = (cat) => {
    revealCatalogSection();
    state.category = cat;
    state.page = 1;
    renderSidebarCategories();
    renderProducts();
  };

  nodes.sidebar?.addEventListener("click", (e) => {
    const btn = e.target.closest("[data-side-category]");
    if (!btn) return;
    setCategory(btn.dataset.sideCategory);
  });

  const focusCatalogResults = () => {
    document.getElementById("catalog-results")?.scrollIntoView({ behavior: "smooth", block: "start" });
  };

  const catalogNavButtons = Array.from(document.querySelectorAll("[data-nav-value]"));
  const catalogNavHint = document.getElementById("catalog-nav-hint");

  const syncCatalogNavButtons = () => {
    let active = "all";
    if (state.purposeFilter) active = `purpose:${state.purposeFilter}`;
    else if (state.category && state.category !== "all") active = `cat:${state.category}`;
    let activeButton = null;
    catalogNavButtons.forEach((btn) => {
      const isActive = btn.dataset.navValue === active;
      btn.classList.toggle("active", isActive);
      if (isActive) activeButton = btn;
    });
    if (activeButton) {
      const parentGroup = activeButton.closest(".products-tree-node");
      if (parentGroup) parentGroup.open = true;
    }
  };

  const applyCatalogNavValue = (value, label = "") => {
    if (!value || value === "all") {
      state.category = "all";
      state.purposeFilter = "";
      state.search = "";
      if (catalogNavHint) catalogNavHint.textContent = "";
    } else if (value.startsWith("cat:")) {
      state.category = value.slice(4) || "all";
      state.purposeFilter = "";
      state.search = "";
      if (catalogNavHint) catalogNavHint.textContent = "";
    } else if (value.startsWith("purpose:")) {
      state.category = "all";
      state.purposeFilter = value.slice(8);
      state.search = "";
      if (catalogNavHint) catalogNavHint.textContent = purposeInfoText(state.purposeFilter);
    }
    if (nodes.search) nodes.search.value = state.search;
    state.activeNavLabel = label || state.activeNavLabel || "";
    state.page = 1;
    syncCatalogNavButtons();
    renderSidebarCategories();
    renderProducts();
    renderProductsShowcase(state.activeNavLabel);
    focusCatalogResults();
  };
  window.__applyCatalogNavValue = applyCatalogNavValue;
  window.__syncCatalogNavButtons = syncCatalogNavButtons;

  catalogNavButtons.forEach((btn) => {
    btn.addEventListener("click", () => {
      applyCatalogNavValue(btn.dataset.navValue || "all", btn.textContent.trim());
    });
  });

  document.querySelector("[data-structure-reset]")?.addEventListener("click", () => {
    state.activeNavLabel = t("catalogNavAll");
    applyCatalogNavValue("all", state.activeNavLabel);
  });
  syncCatalogNavButtons();
  renderTypeProperties();
  window.__renderTypeProperties = renderTypeProperties;
  if (!state.activeNavLabel) state.activeNavLabel = t("catalogNavAll");
  renderProductsShowcase(state.activeNavLabel);
  window.__renderProductsShowcase = renderProductsShowcase;

  document.getElementById("type-props-grid")?.addEventListener("click", (e) => {
    const card = e.target.closest("[data-type-family]");
    if (!card) return;
    const family = card.dataset.typeFamily || "";
    if (!family) return;
    const value = `cat:${family}`;
    applyCatalogNavValue(value, familyI18nLabel(family));
  });

  // Links from tiles/footer jump to selected catalog category
  document.querySelectorAll("[data-side-jump]").forEach((a) => {
    a.addEventListener("click", () => {
      const cat = a.dataset.sideJump;
      if (cat) setCategory(cat);
    });
  });

  // Top nav products dropdown with series selection
  const navProducts = document.querySelector(".nav-products");
  const navProductsToggle = document.getElementById("nav-products-toggle");
  const navProductsMenu = document.getElementById("nav-products-menu");
  const setCategoryAndScroll = (cat, query) => {
    revealCatalogSection();
    state.category = cat;
    state.search = query || "";
    if (nodes.search) nodes.search.value = state.search;
    renderSidebarCategories();
    renderProducts();
    document.getElementById("catalog")?.scrollIntoView({ behavior: "smooth" });
  };

  navProductsToggle?.addEventListener("click", () => {
    navProducts?.classList.toggle("open");
  });
  document.addEventListener("click", (e) => {
    if (!navProducts) return;
    if (!navProducts.contains(e.target)) navProducts.classList.remove("open");
  });
  navProductsMenu?.addEventListener("click", (e) => {
    const typeBtn = e.target.closest("[data-nav-only-family]");
    if (typeBtn) {
      setCategoryAndScroll(typeBtn.dataset.navOnlyFamily, "");
      navProducts?.classList.remove("open");
      return;
    }
    const btn = e.target.closest("[data-nav-family][data-nav-id]");
    if (!btn) return;
    const p = PRODUCTS.find((x) => x.id === btn.dataset.navId);
    setCategoryAndScroll(btn.dataset.navFamily, p?.series || p?.name || "");
    if (p) window.location.href = `product.html?id=${encodeURIComponent(p.id)}`;
    navProducts?.classList.remove("open");
  });

  nodes.customerType?.addEventListener("change", (e) => {
    state.customerType = e.target.value;
    // Чтобы не смешивать цены розницы/опта в одной заявке
    state.cart = [];
    saveCart();
    state.page = 1;
    renderProducts();
    renderAdviceRecommendations();
    renderCart();
  });

  nodes.sortBy?.addEventListener("change", (e) => {
    state.sortBy = e.target.value;
    state.page = 1;
    renderProducts();
  });

  nodes.search?.addEventListener("input", (e) => {
    state.search = e.target.value;
    state.page = 1;
    renderProducts();
  });

  document.querySelectorAll("[data-quick-filter]").forEach((btn) => {
    btn.addEventListener("click", () => {
      document.querySelectorAll("[data-quick-filter]").forEach((b) => b.classList.remove("active"));
      btn.classList.add("active");
      state.quickFilter = btn.dataset.quickFilter || "all";
      state.page = 1;
      renderProducts();
    });
  });

  nodes.products?.addEventListener("click", (e) => {
    const payBtn = e.target.closest("[data-pay]");
    if (payBtn) {
      const id = payBtn.dataset.pay;
      const p = PRODUCTS.find((x) => x.id === id);
      if (!p) return;
      const defPack = defaultPackTypeForCatalog(p);
      if (!defPack) return;
      const can =
        defPack === "bucket"
          ? p.bucketKg != null && calcPackTotal(p, "bucket", state.customerType) != null
          : p.drumKg != null && calcPackTotal(p, "drum", state.customerType) != null;
      if (!can) return;
      addToCart(id, defPack);
      window.location.href = "checkout.html";
      return;
    }
    const addOne = e.target.closest("[data-add-one]");
    if (addOne) {
      const id = addOne.dataset.addOne;
      const pack = addOne.dataset.pack;
      if (id && (pack === "bucket" || pack === "drum")) {
        addToCart(id, pack);
      }
      return;
    }
    const addBtn = e.target.closest("[data-add]");
    if (addBtn) {
      addToCart(addBtn.dataset.add, addBtn.dataset.pack);
      return;
    }
  });

  nodes.adviceReco?.addEventListener("click", (e) => {
    const addBtn = e.target.closest("[data-advice-add]");
    if (!addBtn) return;
    addToCart(addBtn.dataset.adviceAdd, addBtn.dataset.pack || "bucket");
  });

  nodes.pagination?.addEventListener("click", (e) => {
    const btn = e.target.closest("[data-page]");
    if (!btn) return;
    state.page = Number(btn.dataset.page) || 1;
    renderProducts();
  });

  nodes.newsLoadMore?.addEventListener("click", () => {
    state.newsVisibleCount += 6;
    renderNews();
  });

  function bindOpenCart(el) {
    el?.addEventListener("click", (e) => {
      e.preventDefault();
      openCartDrawer();
    });
  }
  bindOpenCart(nodes.openCart);
  nodes.closeCart?.addEventListener("click", () => closeCartDrawer());
  nodes.cartOverlay?.addEventListener("click", (e) => {
    if (e.target === nodes.cartOverlay) closeCartDrawer();
  });
  nodes.cartSortSelect?.addEventListener("change", () => {
    state.cartSort = nodes.cartSortSelect.value;
    localStorage.setItem("cartSort", state.cartSort);
    renderCart();
  });

  nodes.cartPayBtn?.addEventListener("click", () => {
    if (!state.cart.length) return;
    window.location.href = "checkout.html";
  });

  document.addEventListener("keydown", (ev) => {
    if (ev.key === "Escape" && nodes.cartOverlay?.classList.contains("open")) closeCartDrawer();
  });

  function onCartRemoveClick(e) {
    const btn = e.target.closest("[data-remove]");
    if (!btn || !nodes.cartOverlay?.contains(btn)) return;
    e.preventDefault();
    e.stopPropagation();
    const idx = Number(btn.dataset.remove);
    if (!Number.isFinite(idx)) return;
    removeFromCart(idx);
  }
  nodes.cartOverlay?.addEventListener("click", onCartRemoveClick);
  nodes.cartOverlay?.addEventListener("click", (e) => {
    const plus = e.target.closest("[data-qty-inc]");
    if (plus && nodes.cartOverlay?.contains(plus)) {
      e.preventDefault();
      const idx = Number(plus.dataset.qtyInc);
      if (!Number.isFinite(idx) || !state.cart[idx]) return;
      setCartItemQuantity(idx, (Number(state.cart[idx].qty) || 1) + 1);
      return;
    }
    const minus = e.target.closest("[data-qty-dec]");
    if (minus && nodes.cartOverlay?.contains(minus)) {
      e.preventDefault();
      const idx = Number(minus.dataset.qtyDec);
      if (!Number.isFinite(idx) || !state.cart[idx]) return;
      setCartItemQuantity(idx, Math.max(1, (Number(state.cart[idx].qty) || 1) - 1));
    }
  });

  // Product modal
  const productModal = document.getElementById("product-modal");
  const productModalBody = document.getElementById("product-modal-body");
  const productModalTitle = document.getElementById("product-modal-title");
  const closeProductModalBtn = document.getElementById("close-product-modal");

  if (productModal && productModalBody && productModalTitle && closeProductModalBtn) {
    const closeModal = () => {
      productModal.classList.remove("open");
      productModal.setAttribute("aria-hidden", "true");
    };

    closeProductModalBtn.addEventListener("click", closeModal);
    productModal.addEventListener("click", (ev) => {
      if (ev.target === productModal) closeModal();
    });
    document.addEventListener("keydown", (ev) => {
      if (ev.key === "Escape" && productModal.classList.contains("open")) closeModal();
    });

    // Экспорт в замыкание функций ниже
    window.__openProductModal = (productId) => {
      openProductModal(productId, { productModal, productModalBody, productModalTitle });
    };
  }

  nodes.form?.addEventListener("submit", async (e) => {
    e.preventDefault();
    const data = new FormData(nodes.form);
    const payload = Object.fromEntries(data.entries());
    const authIdentity = getLeadFormAuthIdentity();
    if (authIdentity) {
      payload.name = authIdentity.name;
      payload.phone = authIdentity.phone;
      payload.email = authIdentity.email;
    }
    const { cartSnapshot, orderTotal } = buildCartSnapshotForLead();
    payload.cart = state.cart;
    payload.cartSnapshot = cartSnapshot;
    payload.orderTotal = orderTotal;
    payload.createdAt = new Date().toISOString();
    payload.customerType = state.customerType;
    payload.source = "site_form";
    try {
      const leadsUrl =
        typeof window.dpApiUrl === "function" ? window.dpApiUrl("/api/leads") : "/api/leads";
      const leadHeaders = { "Content-Type": "application/json" };
      try {
        const tok = localStorage.getItem("authToken");
        if (tok) leadHeaders.Authorization = `Bearer ${tok}`;
      } catch {
        /* ignore */
      }
      const res = await fetch(leadsUrl, {
        method: "POST",
        headers: leadHeaders,
        body: JSON.stringify(payload),
      });
      if (!res.ok) throw new Error("crm_unavailable");
      nodes.form.reset();
      nodes.formStatus.textContent = t("submitted");
    } catch (_err) {
      // fallback: сохраняем локально, если API не запущен
      localStorage.setItem("lastLead", JSON.stringify(payload));
      nodes.form.reset();
      nodes.formStatus.textContent = `${t("submitted")} (offline mode)`;
    }
  });

  async function submitCartLead() {
    if (!state.cart.length) return;
    const { cartSnapshot, orderTotal } = buildCartSnapshotForLead();
    const { deliveryMethod, paymentMethod } = getCartLeadOptions();
    let name = "";
    let phone = "";
    let email = "";
    try {
      const u = JSON.parse(localStorage.getItem("authUser") || "null");
      if (u) {
        name = String(u.name || "").trim();
        email = String(u.email || "").trim();
        phone = String((u.profile && u.profile.phone) || "").trim();
      }
    } catch {
      /* ignore */
    }
    if (!name || !phone) {
      window.location.href = "contact.html#contact";
      closeCartDrawer();
      return;
    }
    const payload = {
      name,
      phone,
      email,
      comment: "Заявка з кошика (без онлайн-оплати на сайті).",
      cart: state.cart,
      cartSnapshot,
      orderTotal,
      customerType: state.customerType,
      source: "cart_checkout",
      deliveryMethod,
      paymentMethod,
    };
    const leadsUrl = typeof window.dpApiUrl === "function" ? window.dpApiUrl("/api/leads") : "/api/leads";
    const leadHeaders = { "Content-Type": "application/json" };
    try {
      const tok = localStorage.getItem("authToken");
      if (tok) leadHeaders.Authorization = `Bearer ${tok}`;
    } catch {
      /* ignore */
    }
    try {
      const res = await fetch(leadsUrl, {
        method: "POST",
        headers: leadHeaders,
        body: JSON.stringify(payload),
      });
      if (!res.ok) throw new Error("fail");
      state.cart = [];
      saveCart();
      renderCart();
      closeCartDrawer();
      if (nodes.formStatus) nodes.formStatus.textContent = t("submitted");
    } catch {
      localStorage.setItem("lastLead", JSON.stringify(payload));
      state.cart = [];
      saveCart();
      renderCart();
      closeCartDrawer();
      if (nodes.formStatus) nodes.formStatus.textContent = `${t("submitted")} (offline)`;
    }
  }

  nodes.checkout?.addEventListener("click", () => {
    submitCartLead();
  });
}

function initPaymentPage() {
  if (document.body?.dataset?.page !== "payment") return;
  const form = document.getElementById("payment-form");
  const statusEl = document.getElementById("payment-status");
  const summaryEl = document.getElementById("payment-order-summary");
  const totalEl = document.getElementById("payment-order-total");
  if (!form || !summaryEl || !totalEl) return;

  if (!state.cart.length) {
    window.location.replace("index.html");
    return;
  }

  const { cartSnapshot, orderTotal } = buildCartSnapshotForLead();
  summaryEl.innerHTML = cartSnapshot
    .map(
      (row) => `
    <div class="payment-order-line">
      <strong>${escapeHtml(row.title)}</strong>
      <p class="meta">${escapeHtml(row.details)}</p>
      <p class="payment-line-sum">${row.lineTotal == null ? t("askPrice") : formatMoney(row.lineTotal)}</p>
    </div>
  `
    )
    .join("");
  totalEl.textContent = formatMoney(orderTotal);

  form.addEventListener("submit", async (e) => {
    e.preventDefault();
    const data = new FormData(form);
    const payload = Object.fromEntries(data.entries());
    payload.cart = state.cart;
    payload.cartSnapshot = cartSnapshot;
    payload.orderTotal = orderTotal;
    payload.source = "payment_page";
    payload.customerType = state.customerType;
    const delEl = document.getElementById("payment-delivery");
    const payEl = document.getElementById("payment-method");
    if (delEl) payload.deliveryMethod = delEl.value;
    if (payEl) payload.paymentMethod = payEl.value;
    if (!payload.paymentMethod) payload.paymentMethod = "liqpay";
    const cardLast = String(payload.cardLast4 || "").replace(/\D/g, "").slice(0, 4);
    if (payload.paymentMethod === "card_demo") {
      payload.paymentNote = cardLast ? `Демо-оплата: карта *${cardLast}` : "Демо-оплата: без карты";
    } else if (payload.paymentMethod === "iban") {
      payload.paymentNote = "Клієнт обрав оплату на IBAN (підтвердження з банку).";
    } else if (payload.paymentMethod === "liqpay") {
      payload.paymentNote = cardLast
        ? `Картка *${cardLast} (заявка до LiqPay у кабінеті або менеджером).`
        : "LiqPay / картка (деталі у менеджера).";
    } else {
      payload.paymentNote = `Обрана оплата: ${payload.paymentMethod}`;
    }
    delete payload.cardLast4;
    payload.comment = [
      String(payload.comment || "").trim(),
      `Итого по корзине: ${formatMoney(orderTotal)}`,
      payload.paymentNote,
    ]
      .filter(Boolean)
      .join("\n");

    const leadsUrl =
      typeof window.dpApiUrl === "function" ? window.dpApiUrl("/api/leads") : "/api/leads";
    const payLeadHeaders = { "Content-Type": "application/json" };
    try {
      const tok = localStorage.getItem("authToken");
      if (tok) payLeadHeaders.Authorization = `Bearer ${tok}`;
    } catch {
      /* ignore */
    }
    try {
      const res = await fetch(leadsUrl, {
        method: "POST",
        headers: payLeadHeaders,
        body: JSON.stringify(payload),
      });
      if (!res.ok) throw new Error("crm_unavailable");
      state.cart = [];
      saveCart();
      renderCart();
      form.reset();
      if (statusEl) statusEl.textContent = t("submitted");
    } catch (_err) {
      localStorage.setItem("lastLead", JSON.stringify(payload));
      state.cart = [];
      saveCart();
      renderCart();
      form.reset();
      if (statusEl) statusEl.textContent = `${t("submitted")} (offline)`;
    }
  });
}

