function readAuthUserRaw() {
  try {
    if (!localStorage.getItem("authToken")) return null;
    const u = JSON.parse(localStorage.getItem("authUser") || "null");
    return u && typeof u === "object" ? u : null;
  } catch {
    return null;
  }
}

/** Данные для заявки: любой вошедший пользователь (есть токен и запись user). */
function getLeadFormAuthIdentity() {
  if (!localStorage.getItem("authToken")) return null;
  const u = readAuthUserRaw();
  if (!u) return null;
  const hasId = u.id != null && String(u.id) !== "";
  const email = String(u.email || "").trim();
  if (!hasId && !email) return null;
  const fullName = String(u.name || "").trim();
  const first = String(u.firstName || u.first_name || "").trim();
  const last = String(u.lastName || u.last_name || "").trim();
  const composed = [first, last].filter(Boolean).join(" ").trim();
  const phone = String((u.profile && u.profile.phone) || u.phone || "").trim();
  const name =
    fullName || composed || (email && email.includes("@") ? email.split("@")[0] : "") || "Клиент";
  return { name, phone, email };
}

function initLeadFormIdentityUI() {
  const form = document.getElementById("lead-form");
  if (!form) return;
  const wrap = form.querySelector("[data-lead-identity]");
  const hint = form.querySelector("[data-lead-auth-hint]");
  const nameIn = form.querySelector('input[name="name"]');
  const phoneIn = form.querySelector('input[name="phone"]');
  if (!wrap || !nameIn || !phoneIn) return;

  if (getLeadFormAuthIdentity()) {
    wrap.hidden = true;
    if (hint) hint.hidden = false;
    nameIn.removeAttribute("required");
    phoneIn.removeAttribute("required");
  } else {
    wrap.hidden = false;
    if (hint) hint.hidden = true;
    nameIn.setAttribute("required", "");
    phoneIn.setAttribute("required", "");
  }
}

window.initLeadFormIdentityUI = initLeadFormIdentityUI;

function initContactCallbackBanner() {
  if (document.body?.dataset?.page !== "contact") return;
  const btn = document.getElementById("contact-cta-callback");
  const statusEl = document.getElementById("contact-cta-callback-status");
  if (!btn) return;
  btn.addEventListener("click", async () => {
    const topicCallback = t("contactCallbackTopic");
    const auth = getLeadFormAuthIdentity();
    if (auth) {
      const payload = {
        name: auth.name,
        phone: auth.phone,
        email: auth.email,
        comment: t("contactCallbackComment"),
        source: "site_callback_banner",
        topic: topicCallback,
        customerType: state.customerType,
        cart: [],
        cartSnapshot: [],
        orderTotal: null,
      };
      if (!String(payload.phone || "").trim()) {
        if (statusEl) {
          statusEl.hidden = false;
          statusEl.textContent = t("contactCallbackNeedPhone");
          statusEl.classList.add("contact-cta-callback-status--err");
        }
        document.getElementById("lead-form")?.scrollIntoView({ behavior: "smooth" });
        return;
      }
      if (statusEl) {
        statusEl.hidden = true;
        statusEl.textContent = "";
        statusEl.classList.remove("contact-cta-callback-status--err");
      }
      btn.disabled = true;
      try {
        const leadsUrl =
          typeof window.dpApiUrl === "function" ? window.dpApiUrl("/api/leads") : "/api/leads";
        const leadHeaders = { "Content-Type": "application/json" };
        try {
          const tok = localStorage.getItem("authToken");
          if (tok) leadHeaders.Authorization = `Bearer ${tok}`;
        } catch {
          /* ignore */
        }
        const res = await fetch(leadsUrl, {
          method: "POST",
          headers: leadHeaders,
          body: JSON.stringify(payload),
        });
        if (!res.ok) {
          const err = await res.json().catch(() => ({}));
          throw new Error(err.message || "fail");
        }
        if (statusEl) {
          statusEl.hidden = false;
          statusEl.textContent = t("contactCallbackSent");
          statusEl.classList.remove("contact-cta-callback-status--err");
        }
      } catch {
        if (statusEl) {
          statusEl.hidden = false;
          statusEl.textContent = t("contactCallbackErr");
          statusEl.classList.add("contact-cta-callback-status--err");
        }
      } finally {
        setTimeout(() => {
          btn.disabled = false;
        }, 400);
      }
    } else {
      const form = document.getElementById("lead-form");
      const topicIn = form?.querySelector('input[name="topic"]');
      if (topicIn) topicIn.value = topicCallback;
      form?.scrollIntoView({ behavior: "smooth" });
      if (statusEl) {
        statusEl.hidden = false;
        statusEl.textContent = t("contactCallbackScrollHint");
        statusEl.classList.remove("contact-cta-callback-status--err");
      }
      const wrap = form?.querySelector("[data-lead-identity]");
      if (wrap && !wrap.hidden) {
        form?.querySelector('input[name="name"]')?.focus();
      } else {
        form?.querySelector('textarea[name="comment"]')?.focus();
      }
    }
  });
}

