function initCarousel() {
  const carousel = document.getElementById("main-carousel");
  if (!carousel) return;

  const slides = Array.from(carousel.querySelectorAll(".carousel-slide"));
  const dotsRoot = document.getElementById("carousel-dots");
  if (!slides.length || !dotsRoot) return;

  const section = carousel.closest(".section") || document;
  const prevBtn = section.querySelector(".carousel-prev");
  const nextBtn = section.querySelector(".carousel-next");

  let current = slides.findIndex((s) => s.classList.contains("active"));
  if (current < 0) current = 0;

  dotsRoot.innerHTML = "";
  const dots = slides.map((_, i) => {
    const d = document.createElement("button");
    d.type = "button";
    d.className = "carousel-dot";
    d.setAttribute("aria-label", `Slide ${i + 1}`);
    d.addEventListener("click", () => setIndex(i));
    dotsRoot.appendChild(d);
    return d;
  });

  function setIndex(i) {
    slides[current].classList.remove("active");
    dots[current]?.classList.remove("active");
    current = (i + slides.length) % slides.length;
    slides[current].classList.add("active");
    dots[current]?.classList.add("active");
  }

  dots[current]?.classList.add("active");
  prevBtn?.addEventListener("click", () => setIndex(current - 1));
  nextBtn?.addEventListener("click", () => setIndex(current + 1));

  // auto-advance
  let timer = setInterval(() => setIndex(current + 1), 7500);
  carousel.addEventListener("mouseenter", () => clearInterval(timer));
  carousel.addEventListener("mouseleave", () => {
    timer = setInterval(() => setIndex(current + 1), 7500);
  });
}

function heroSlideshowEasingCss(easing) {
  const key = String(easing || "smooth");
  if (key === "smooth") return "cubic-bezier(0.22, 1, 0.36, 1)";
  return key;
}

function readHeroSlideshowSettings() {
  const s = window.DP_HERO_SLIDESHOW_SETTINGS;
  const d = { intervalMs: 5500, transitionMs: 1050, easing: "smooth" };
  if (!s || typeof s !== "object") return d;
  let intervalMs = Number(s.intervalMs);
  if (!Number.isFinite(intervalMs)) intervalMs = d.intervalMs;
  intervalMs = Math.min(120000, Math.max(2000, Math.round(intervalMs)));
  let transitionMs = Number(s.transitionMs);
  if (!Number.isFinite(transitionMs)) transitionMs = d.transitionMs;
  transitionMs = Math.min(5000, Math.max(150, Math.round(transitionMs)));
  const allowed = new Set(["linear", "ease", "ease-in", "ease-out", "ease-in-out", "smooth"]);
  let easing = String(s.easing || "").trim();
  if (!allowed.has(easing)) easing = d.easing;
  return { intervalMs, transitionMs, easing };
}

function applyHeroSlideshowSettingsFromSite() {
  const { transitionMs, easing } = readHeroSlideshowSettings();
  const fade = `${transitionMs}ms`;
  const ease = heroSlideshowEasingCss(easing);
  document.querySelectorAll("[data-dp-hero-fade-root]").forEach((el) => {
    el.style.setProperty("--hero-slide-fade", fade);
    el.style.setProperty("--hero-slide-ease", ease);
  });
}

function initHeroShowcaseSlideshow() {
  const root = document.getElementById("hero-showcase-slideshow");
  const dotsRoot = document.getElementById("hero-showcase-slideshow-dots");
  if (!root || !dotsRoot) return;

  const slides = Array.from(root.querySelectorAll(".hero-showcase-slide"));
  if (slides.length < 2) return;

  const prevBtn = document.querySelector(".hero-showcase-slideshow__btn--prev");
  const nextBtn = document.querySelector(".hero-showcase-slideshow__btn--next");
  const host = root.closest(".hero-showcase-media");
  const { intervalMs, transitionMs } = readHeroSlideshowSettings();

  let current = slides.findIndex((s) => s.classList.contains("is-active"));
  if (current < 0) current = 0;
  slides.forEach((s, i) => s.classList.toggle("is-active", i === current));

  dotsRoot.innerHTML = "";
  const dots = slides.map((_, i) => {
    const d = document.createElement("button");
    d.type = "button";
    d.className = "hero-showcase-slideshow__dot";
    if (i === current) d.classList.add("is-active");
    d.addEventListener("click", () => setIndex(i));
    dotsRoot.appendChild(d);
    return d;
  });

  const reduceMotion = window.matchMedia?.("(prefers-reduced-motion: reduce)")?.matches;
  const HERO_SLIDE_FADE_MS = transitionMs;
  const leaveTimers = new WeakMap();

  function clearLeaveTimer(slide) {
    const id = leaveTimers.get(slide);
    if (id != null) {
      clearTimeout(id);
      leaveTimers.delete(slide);
    }
  }

  function setIndex(i) {
    const n = (i + slides.length) % slides.length;
    if (n === current) return;

    const leaving = slides[current];
    clearLeaveTimer(leaving);

    if (reduceMotion) {
      leaving.classList.remove("is-active", "is-leaving");
      dots[current]?.classList.remove("is-active");
      current = n;
      slides[current].classList.add("is-active");
      dots[current]?.classList.add("is-active");
      return;
    }

    leaving.classList.remove("is-active");
    leaving.classList.add("is-leaving");

    dots[current]?.classList.remove("is-active");
    current = n;
    slides[current].classList.add("is-active");
    dots[current]?.classList.add("is-active");

    const t = setTimeout(() => {
      leaving.classList.remove("is-leaving");
      leaveTimers.delete(leaving);
    }, HERO_SLIDE_FADE_MS);
    leaveTimers.set(leaving, t);
  }

  function updateSlideshowDotLabels() {
    dots.forEach((d, idx) => {
      d.setAttribute("aria-label", `${t("heroSlide")} ${idx + 1}`);
    });
  }

  window.__updateHeroShowcaseSlideshowI18n = updateSlideshowDotLabels;
  updateSlideshowDotLabels();

  prevBtn?.addEventListener("click", () => setIndex(current - 1));
  nextBtn?.addEventListener("click", () => setIndex(current + 1));

  root.addEventListener("keydown", (e) => {
    if (e.key === "ArrowLeft") {
      e.preventDefault();
      setIndex(current - 1);
    }
    if (e.key === "ArrowRight") {
      e.preventDefault();
      setIndex(current + 1);
    }
  });

  let timer = null;

  function startAutoplay() {
    if (reduceMotion) return;
    clearInterval(timer);
    timer = setInterval(() => setIndex(current + 1), intervalMs);
  }

  function stopAutoplay() {
    clearInterval(timer);
    timer = null;
  }

  if (!reduceMotion) {
    startAutoplay();
    host?.addEventListener("mouseenter", stopAutoplay);
    host?.addEventListener("mouseleave", startAutoplay);
  }
}

function applyHeroSlidesFromSite() {
  const root = document.getElementById("hero-showcase-slideshow");
  if (!root) return;
  const incoming = Array.isArray(window.DP_HERO_SLIDES) ? window.DP_HERO_SLIDES : [];
  const slides = incoming
    .map((row) => {
      if (!row || typeof row !== "object") return null;
      const url = String(row.url || "").trim();
      if (!url) return null;
      return {
        id: String(row.id || "").trim(),
        url,
        alt: String(row.alt || "").trim(),
      };
    })
    .filter(Boolean)
    .slice(0, 12);
  if (!slides.length) return;
  const resolve = typeof window.dpResolveMediaUrl === "function" ? window.dpResolveMediaUrl : (x) => x;
  root.innerHTML = slides
    .map((s, idx) => {
      const active = idx === 0 ? " is-active" : "";
      const cls = String.fromCharCode("a".charCodeAt(0) + (idx % 26));
      const alt = s.alt || "";
      return `
                <div class="hero-showcase-slide${active}">
                  <img
                    class="hero-showcase-media-img hero-showcase-media-img--slide-${cls}"
                    src="${escapeHtml(resolve(s.url))}"
                    alt="${escapeHtml(alt)}"
                    width="1024"
                    height="682"
                    loading="${idx === 0 ? "eager" : "lazy"}"
                    decoding="async"
                  />
                </div>`;
    })
    .join("");
}

